        tog = tk.Frame(sec, bg="#0e0e10")
        tog.pack(fill="x", pady=(2, 0))
        self.toggle_btn = tk.Label(tog, text="👁 Show Token", font=("Segoe UI", 9),
            fg="#72767d", bg="#0e0e10", cursor="hand2")
        self.toggle_btn.pack(anchor="e")
