        title_frame = tk.Frame(self.settings_frame, bg="#0e0e10")
        title_frame.pack(fill="x", pady=(18, 5))

        back_btn = tk.Button(title_frame, text="🡨 Back", font=("Segoe UI", 10, "bold"),
            bg="#2f3136", fg="#dcddde", relief="flat", cursor="hand2",
            activebackground="#3f4147", activeforeground="#dcddde",
            command=self.go_to_main, padx=10, pady=4)
        back_btn.pack(side="left", padx=40)

        tk.Label(title_frame, text="Settings", font=("Segoe UI", 18, "bold"),
                 fg="#dcddde", bg="#0e0e10").pack(side="left", padx=(10, 0))
                 
        tk.Frame(self.settings_frame, bg="#2f3136", height=1).pack(fill="x", padx=40, pady=12)

        # ── Settings Options ──
        settings_sec = tk.Frame(self.settings_frame, bg="#0e0e10")
        settings_sec.pack(fill="both", expand=True, padx=40, pady=(0, 5))

